prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?orgId ?orgName ?modelName ?origId ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(?orgId = "c41660388a04449a995dccf97d894f46")
  OPTIONAL { ?org bbo:name ?orgName . }
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:originalId ?origId ;
         tai:modelCreated ?created .
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?participant) AS ?participantCount)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "c41660388a04449a995dccf97d894f46" ;
       tai:belongsTo* ?corpus .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:belongsTo* ?corpus .
  ?defs tai:belongsTo ?model ;
        tai:belongsTo* ?corpus .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?participant a bboExt:Participant ; tai:belongsTo ?choreo . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?kind
  ?name
  (COUNT(*) AS ?cnt)
WHERE {
  {
    SELECT "participant" AS ?kind ?name (COUNT(*) AS ?cnt) WHERE {
      ?org a bboExt:Organization ;
           tai:organizationId "c41660388a04449a995dccf97d894f46" .
      ?model a bboExt:Model ;
             tai:belongsTo ?org ;
             tai:belongsTo* ?anyRoot .
      ?defs tai:belongsTo ?model ;
            tai:belongsTo* ?anyRoot .
      ?choreo a bboExt:Choreography ;
              tai:belongsTo ?defs .
      ?participant a bboExt:Participant ;
                   tai:belongsTo ?choreo ;
                   bbo:name ?name .
      FILTER(STRLEN(STR(?name)) > 0)
    }
    GROUP BY ?name
  }
  UNION
  {
    SELECT "task" AS ?kind ?name (COUNT(*) AS ?cnt) WHERE {
      ?org a bboExt:Organization ;
           tai:organizationId "c41660388a04449a995dccf97d894f46" .
      ?model a bboExt:Model ;
             tai:belongsTo ?org .
      ?defs tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ;
              tai:belongsTo ?defs .
      ?task a bboExt:ChoreographyTask ;
            tai:belongsTo ?choreo ;
            bbo:name ?name .
      FILTER(STRLEN(STR(?name)) > 0)
    }
    GROUP BY ?name
  }
}
GROUP BY ?kind ?name
ORDER BY DESC(?cnt)
LIMIT 25

